module RefModule (
    Q      ,
    CLK    ,
    D      ,
    RESET  ,
    SET
);

    output Q      ;
    input  CLK    ;
    input  D      ;
    input  RESET  ;
    input  SET    ;

    reg Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RESET or posedge SET or posedge dbg_halt) begin
        if (RESET) begin
            Q <= 0;
        end else if (SET) begin
            Q <= 1;
        end else begin
            Q <= D;
        end
    end

endmodule
